ture": "https://media.licdn.com/dms/image/v2/D4E03AQGNgIZmD-vdDg/profile-displayphoto-shrink_400_400/profile-displayphoto-shrink_400_400/0/1677690653009?e=1778112000&v=beta&t=vlbOuk1Tf-0dpIgreYoW9DFzXjyHITGhe9_RlIiBY5Y", "peopleAlsoViewed/24/public_identifier": "sahil-dutta-b6b91a14", "peopleAlsoViewed/24/url": "https://linkedin.com/in/ACoAAAL7xwMBmhRW3WI76LYbNXoEQOJ5dNynVTg", "peopleAlsoViewed/25/entity_urn": "urn:li:fsd_profile:ACoAABFKc_wBW6Xuri086bOhVKzy4luq8lci5dk", "peopleAlsoViewed/25/first_name": "Manop", "peopleAlsoViewed/25/follower_count": "780", "peopleAlsoViewed/25/headline": "Cluster General Manager Hotel/Resort", "peopleAlsoViewed/25/last_name": "Wongchaikam", "peopleAlsoViewed/25/premium": "false", "peopleAlsoViewed/25/profile_picture": "https://media.licdn.com/dms/image/v2/D5603AQFfVSeB_mDOKQ/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1708815171480?e=1778112000&v=beta&t=aCDyYdRVjk_WkrZLQW8kK2b0WdnjhZTrUBdT21JsZOU", "peopleAlsoViewed/25/public_identifier": "manop-wongchaikam-3b819981", "peopleAlsoViewed/25/url": "https://linkedin.com/in/ACoAABFKc_wBW6Xuri086bOhVKzy4luq8lci5dk", "profilePic": "https://media.licdn.com/dms/image/v2/D5603AQFeWXvMHDZVyg/profile-displayphoto-crop_800_800/B56ZnDniZOHQAI-/0/1759923546581?e=1778112000&v=beta&t=iKizkthY2KC_D-MjqqbBhgbW5hMH3I2q57Aoi3br0eg", "profilePicHighQuality": "https://media.licdn.com/dms/image/v2/D5603AQFeWXvMHDZVyg/profile-displayphoto-crop_800_800/B56ZnDniZOHQAI-/0/1759923546581?e=1778112000&v=beta&t=iKizkthY2KC_D-MjqqbBhgbW5hMH3I2q57Aoi3br0eg", "publicIdentifier": "yogi-rana-a403a518", "recommendations/0/context": "Yogi was senior to Ritin but didn't manage Ritin directly", "recommendations/0/date": "February 2, 2021", "recommendations/0/description": "Ritin joined the hotel school 2 students intake after my course.\n\nThe hotel school being 4 years course allowed him to work on many food and beverage related projects as part of my team.\n\nRitin always came across as a thorough hospitality professional and willing to learn at every opportunity given to him. \n\nA great team player, able to deliver under pressure. \n\nThe Teams he worked with had always good things to say about Ritin’s professional approach at all levels of responsibilities assigned to him. \n\nHe has a Good eye for detail and able to deliver projects in time. \n\nRitin kept in touch with me after college for professional career advise shows his willingness to learn from others and their experiences.\n\n\nI have no hesitation in recommending Ritin to any organization looking for highly talented, motivated manager who is a great team player and at the same\nTime fun to work with. \n\nHe is multi skilled and always ready to try new things.\n\nMy best wishes to Ritin in his professional career and I look forward to see him progressing in his career and lead successful and highly productive teams.", "recommendations/0/name": "Ritin S.", "recommendations/0/subtitle": "Venue Manager @ Latitude 32 | Masters in Hospitality Management", "recommendations/0/url": "https://www.linkedin.com/in/ritin-s-8405931b/", "recommendations/0/urn": "urn:li:fsd_profile:ACoAAAQt3fAB8Z2fqTW71meAWDN3GsZg-k7zIqY", "recommendations/1/context": "Yogi worked with Ansen on the same team", "recommendations/1/date": "December 7, 2019", "recommendations/1/description": "I worked with Ansen at Hilton Ras Al Khaimah Resort and Spa, I can say without any doubt that Ansen is one of the Best HR manager I worked with, Fair in his dealing with team, thorough knowledge of HR related system, great motivator and always keen to help departments and team members. Takes initiative to organise team events and recognise team members. Great understanding of hospitality industry and recruitment needs to hire the best talent available.\n\nAnsen is a talented HR manager, hard working, sincere, honest ,approachable, Seasoned and works well with various operational functions of a hotel.\n\nI highly recommend Ansen as he is a great asset for any organisation he works for.\n", "recommendations/1/name": "Ansen Sousa", "recommendations/1/subtitle": "Head Of Human Resources | MBA - HR", "recommendations/1/url": "https://www.linkedin.com/in/ansensousa/", "recommendations/1/urn": "urn:li:fsd_profile:ACoAAAVddakBRQjVF1ursFC_Oh0MVA5Gzj8UV_o", "recommendations/2/context": "Yogi managed Muhammad Fazli directly", "recommendations/2/date": "October 17, 2019", "recommendations/2/description": "I worked with Fazli during my tenure at Jumeirah hotels. Fazli is a hard working chef who can be trusted to perform a task without watching over him. He is passionate about cooking and takes pride in his dishes. Fazli works well within a team setting and a good team player. Good undertaking of cooking methods and their application. He was trusted by his team members, able to work under pressure and deliver when needed.\nI will have no hesitation in recommending Fazli to any employer as he will be an asset to the team.", "recommendations/2/name": "Muhammad Fazli Idris", "recommendations/2/subtitle": "Culinary Director & Owner", "recommendations/2/url": "https://www.linkedin.com/in/fazliidris/", "recommendations/2/urn": "urn:li:fsd_profile:ACoAABQ-EWsB2GLHHrRohirrjXXspgxhALWgBcY", "recommendations/3/context": "Yogi was senior to Ajeev but didn't manage Ajeev directly", "recommendations/3/date": "July 22, 2013", "recommendations/3/description": "Ajeev from Day 1 came across as one of the most professional Restaurant Managers I have worked in the hospitality Industry. Ajeev is highly dedicated to make the restaurant a success and ensured \" piaceri da gustare\" archives the no. 1 title for the Italian restaurant in the region and also acihieves the budgets well above. Ajeev always communicates with the guests and is very active in communicating guests prefrences to the kitchen. As a restaurant manager his restaurant always had a flawless service with attention to details and guest satisfaction being Ajeev's priority. He came across to be very creative with his table set ups especially with VIP guests and celebrations hosted by the guests. Apart from restaurant Ajeev was also involved in training line colleagues for service and revenue based trainings. He was a strong force to make the Italian food festival a big success and ensured the P&L look very healthy. Takes initiative, leads by example, An able manager with strong knowledge of f&b and somebody you can trust fully to run the restaurant profitably and to maximum guest satisfaction. I have no hesitation in recommending Ajeev for a senior role as I feel he is ready for it and will put h best foot forward . I will have no hesitation n employing Ajeev if any opportunity arises in future. An overall star performer in F&B department who am sure will do very good in future. I wish him good luck.", "recommendations/3/name": "Ajeev Bhugawoo", "recommendations/3/subtitle": "Operations Manager", "recommendations/3/url": "https://www.linkedin.com/in/ajeev-bhugawoo-6485901b/", "recommendations/3/urn": "urn:li:fsd_profile:ACoAAAQtyJgBn3coXlDqsR_BKR_GqelmqXPUCOY", "recommendations/4/context": "Yogi managed Sudhanshu directly", "recommendations/4/date": "June 26, 2013", "recommendations/4/description": "I had a chance to recruit Sudhanshu as Sous Chef from the Park Sheraton in London for the Hilton Ras Al Khaimah Resort & Spa.  He Directly reported to me.\nSudhanshu was Incharge for assisting me in running the Resort Kitchen Operation and Directly responsible for the 13 F&B outlets kitchens in the Resort. He is dedicated, Hard working, Creative  and trust worthy. In a short time he mrked his stamp on the Resort kitchen operation and was instrumental in the menus changes for all outlets. Sudhanshu has a good working knowledge of the European cuisine along with International Cuisine. \nSudhanshu also has a good understanding of the kitchen management and the commercial side of the kitchen to manage food cost. He was well respected among his sub ordinates and popular amongst his colleagues and leads by example.\n\n100% commited Individual , whom I Highly recommend and will be an asset to any Big hotel Chain or Organisation. If I had a chance I will not hesitate to employe Sudhanshu in a senior role in my team.\n\nI wish Sudhanshu Good Luck.", "recommendations/4/name": "Sudhanshu Nirmal", "recommendations/4/subtitle": "Executive Chef at the iconic Sheraton Grand Sydney Hyde Park🇮🇳🇬🇧🇦🇪🇦🇺", "recommendations/4/url": "https://www.linkedin.com/in/sudhanshu-nirmal-5b936a12/", "recommendations/4/urn": "urn:li:fsd_profile:ACoAAAKLcN0Bj66RIZU5BGvJRts71ECKgpr8KrM", "recommendations/5/context": "Yogi was senior to Pawan but didn't manage Pawan directly", "recommendations/5/date": "October 22, 2011", "recommendations/5/description": "I have known Pawan from Jumeirah Bab al shams. He worked at the Itlian restaurant and pretty much managed the restaurant in absence of a senior chef in that restaurant. Pawan has always been a stickler to standards and always delivered good quality Italian food which was appreciated by the guest.\n\nPawan is capable of managing food cost for an outlet and has a great understanding of the financial side in whole, \nI came across Pawan as an individual with posititve outlook, can do attitude, hard working, sincere, honest and guest oriented.\n\nI wish Pawan good luck in his future assignments\n\nYogi", "recommendations/5/name": "Pawan Ailawadi", "recommendations/5/subtitle": "Focus and Believe", "recommendations/5/url": "https://www.linkedin.com/in/pawan-ailawadi-7237b834/", "recommendations/5/urn": "urn:li:fsd_profile:ACoAAAc8yQsBOY3TNHLz4l3d2ouQ21BLtlk-59A", "recommendations/6/context": "Yogi managed Pooja directly", "recommendations/6/date": "June 3, 2011", "recommendations/6/description": "Pooja worked in masala restaurant as a trainee in both Back of the house and front of the house, she excels in her customer handling skills and has an excellent eye to detail. Pooja is hard working, committed and has a drive to excel in whatever she does. she aims for perfection in her work and looks for the same from others working along wit her. I am sure she will do very well in her feild of expertise. I wish her good luck in her journey to excellence.\nYoginder Rana", "recommendations/6/name": "Pooja Vora", "recommendations/6/subtitle": "Enterprise Team Leader MEAAPAC", "recommendations/6/url": "https://www.linkedin.com/in/vorapooja/", "recommendations/6/urn": "urn:li:fsd_profile:ACoAAAWhoVkB0VwjekkfGdZHfrxDZi51jXst1Cg", "recommendations/7/context": "Yogi managed Pawan directly", "recommendations/7/date": "May 28, 2011", "recommendations/7/description": "Pawan had worked as a trainee in my kitchen brigade, He is a commited colleague. Always eager to take responsibilties and completes the task he is provided. Guest oriented and belives in going an extra mile, hardworking, knowledgable and a fully dedicated colleague. Would be an asset to an organisation.\nYoginder Rana", "recommendations/7/name": "Pawan Kalyani", "recommendations/7/subtitle": "Founder - TOGETHER Inc.", "recommendations/7/url": "https://www.linkedin.com/in/pawankalyani/", "recommendations/7/urn": "urn:li:fsd_profile:ACoAAAKNeowB9bTPax9CPXLcLg58hjhF_kJhWXk", "recommendationsReceived/0/context": "Phil managed Yogi directly", "recommendationsReceived/0/date": "September 5, 2025", "recommendationsReceived/0/description": "Yogi is not only a wonderful person but also a very talented one. I had the pleasure to work with him and always found him to be passionate , committed and very hard working.\nWho ever he works with won’t ever forget the time spent with him. A coach and a man who continually strives to learn and share his knowledge ", "recommendationsReceived/0/name": "Phil Broad", "recommendationsReceived/0/subtitle": "Senior Executive | Expert in F&B, Retail & Hospitality | Transforming Global Brands Through Strategic Growth, Franchise Development & Customer-Centric Innovation", "recommendationsReceived/0/url": "https://www.linkedin.com/in/phil-broad-9b42b412/", "recommendationsReceived/0/urn": "urn:li:fsd_profile:ACoAAAKJE5gBUwq757pSLhti0GEK5e-acKMIZek", "recommendationsReceived/1/context": "Pritam worked with Yogi on the same team", "recommendationsReceived/1/date": "August 13, 2014", "recommendationsReceived/1/description": "I worked with Yogi for a very short period however, when dealing with him. Yogi has been very professional, focused on his job 100%, extremely committed, dedicated and hardworking, Yogi was a pre-opening team member. Yogi is a great person to work with as a professional and friend.", "recommendationsReceived/1/name": "Pritam Lopes", "recommendationsReceived/1/subtitle": "Global HR &L&D Leader | MBA | CIPD | Strategist | Empowering People, Enabling Performance | Driving Talent, Culture & Change for Business Growth", "recommendationsReceived/1/url": "https://www.linkedin.com/in/pritam-lopes-191ab711/", "recommendationsReceived/1/urn": "urn:li:fsd_profile:ACoAAAJ58z0BdMvEybiCNQuK0hADYhKkh2B5bUo", "recommendationsReceived/2/context": "Ansen worked with Yogi on the same team", "recommendationsReceived/2/date": "July 13, 2014", "recommendationsReceived/2/description": "Yogi is one of the most promising chefs I have ever come across. Besides being a joy to work with, Yogi is a take-charge person who is able to present creative ideas in the culinary art. He has successfully developed several Strategic plans for our company's culinary team that have resulted in increased revenue.\n\nIt was a great pleasure working with Yogi and I would highly recommend him to any company in the world.", "recommendationsReceived/2/name": "Ansen Sousa", "recommendationsReceived/2/subtitle": "Head Of Human Resources | MBA - HR", "recommendationsReceived/2/url": "https://www.linkedin.com/in/ansensousa/", "recommendationsReceived/2/urn": "urn:li:fsd_profile:ACoAAAVddakBRQjVF1ursFC_Oh0MVA5Gzj8UV_o", "recommendationsReceived/3/context": "Inder managed Yogi directly", "recommendationsReceived/3/date": "June 27, 2013", "recommendationsReceived/3/description": "Chef Yogi - One will rarely find a complete chef who is equally good in executing responsibilities, quality assurance, team synergy and coordination with customers. He was my most trusted chef to leave responsibilities to him. He has never let me down. Great going.....keep up.", "recommendationsReceived/3/name": "Inder Dev", "recommendationsReceived/3/subtitle": "A Seasoned Culinaire nurtured at Brands HCI, Hokke Hotels Japan, ITC Luxury, Oberoi-Hilton, Radisson…F&B Concepts Creator. Pre-opening & Turn Around expert. Award winning & India’s most creative culinaire, Food stylist.", "recommendationsReceived/3/url": "https://www.linkedin.com/in/inder-dev-05b8234/", "recommendationsReceived/3/urn": "urn:li:fsd_profile:ACoAAADVVocBWii0XEbn9jTdiAjohI6C6-iNfiY", "recommendationsReceived/4/context": "Murray was senior to Yogi but didn't manage Yogi directly", "recommendationsReceived/4/date": "July 24, 2012", "recommendationsReceived/4/description": "In the short time that Yogi and I worked together at Jumeirah restaurants he greatly impressed me with the dedication he showed to his job , his knowledge , and passion for people and food . He was a well respected colleague and friend to many , always happy to discuss and pass on his considerable knowledge to others . Yogi will not let something rest until it is right , he will work tirelessly to complete projects , and shows great attention to detail .", "recommendationsReceived/4/name": "Murray Rea", "recommendationsReceived/4/subtitle": "Chief Operations Officer MUVI Cinemas KSA", "recommendationsReceived/4/url": "https://www.linkedin.com/in/murray-rea-3440a928/", "recommendationsReceived/4/urn": "urn:li:fsd_profile:ACoAAAW1aKQBZW0UGTOHVmUgM_mmIY0r6qNMjGE", "recommendationsReceived/5/context": "Esha worked with Yogi but on different teams", "recommendationsReceived/5/date": "August 9, 2011", "recommendationsReceived/5/description": "Yogi Rana is a very professional and hardworking colleague. He beleived in continuous innovation and introduced new food and techniques in his food. Yogi strongly beleives in training and developing his team members and is a strong team player. He was incharge or food safety and HACCP for the resort and implemented a number of systems to follow food safety standards. Yogi is a people's person and enjoys networking with guests and friends. A number of guests still ask for him and his food at Masala. Yogi has a huge potential and works with full dedication to every project that he does.", "recommendationsReceived/5/name": "Esha Bhatnagar", "recommendationsReceived/5/subtitle": "Business Transformation and People Transformation Expert", "recommendationsReceived/5/url": "https://www.linkedin.com/in/eshabhatnagar/", "recommendationsReceived/5/urn": "urn:li:fsd_profile:ACoAAAO6vAMBC10FsZ1OGA9za33pRr02GGFw9oY", "recommendationsReceived/6/context": "Vijayan worked with Yogi on the same team", "recommendationsReceived/6/date": "July 26, 2011", "recommendationsReceived/6/description": "I had the opportunity to be  a part of Yogi's recruitment process at Jumeirah Bab Al Shams Desert Resort & Spa from Welcome group in India where he was noted as highly accomplished Managment Graduate and high potential. And am proud that we could get him to join us\n\nHe was recruited to set up and open Masala Restaurant, a outlet which surpassed service, product, profut and people results i  ashort period from opening. Dedication, structured approach with a innovative streak are traits in him that contributed to the outlet being a success story and recipient of many awards\n\nYogi moved on from Bab Al Shams to take up the role of Brand Chef with Jumeirah Restaurants and has again been identifed as high potential colleague who is in the process of being in key leadership role soon.\n\nYogi leaves no effort in ensuring he is always up to date with trends, takes every opportunity to gain knowledge & skills, is detail oriented and has the want to successd and exceed expectations. He is a professional in all ways, a effective trainer and someone who is passionate about what he does. I strongly believe he has build hios leadersgip skills over the last yers and is now ready for senior roles\n\nWish him the very best", "recommendationsReceived/6/name": "Vijayan B.", "recommendationsReceived/6/subtitle": "Vice President Human Resources", "recommendationsReceived/6/url": "https://www.linkedin.com/in/vijayan-b-15453a16/", "recommendationsReceived/6/urn": "urn:li:fsd_profile:ACoAAANIU1ABKxNfek6M_S6ru2iFua1-p-G3czE", "recommendationsReceived/7/context": "Ish was senior to Yogi but didn't manage Yogi directly", "recommendationsReceived/7/date": "May 29, 2011", "recommendationsReceived/7/description": "I have had the pleasure of working with Chef Yogi at Jumeirah Restaurants in his capacity of Brand Chef. Chef Yogi always demonstrates passion, professionalism and commitment in all the tasks he is assigned to. He also possesses a very broad understanding of the commercial world with a willingness to learn more.", "recommendationsReceived/7/name": "Ish Makda FCMA, CGMA", "recommendationsReceived/7/subtitle": "Hospitality Expert | Senior Level Leadership | Business Transformation | Financial Management | Hotel Management | Project Management | Business Process Redesign | Cross Functional Collaboration", "recommendationsReceived/7/url": "https://www.linkedin.com/in/ishm/", "recommendationsReceived/7/urn": "urn:li:fsd_profile:ACoAAAJKJBABlHKNB_EkhkLnLZ593WTfN9it4jY", "recommendationsReceived/8/context": "Andrew managed Yogi directly", "recommendationsReceived/8/date": "May 28, 2011", "recommendationsReceived/8/description": "Yogi is a 100% committed individual who is determined to succeed in whatever he does or whatever task he is given.\nI had very much found Yogi to be an asset to my team and a strong leader of a large brigade. He would be a tremendous asset to anyone that employs him and if an opportunity should arise I would have no hesitation in re employing yogi as a senior member of my team once again.\nLoyal, hardworking, knowledgeable, strong leader and motivator and true creative spirit, I wish him all the best in his future endeavors.\n\nAndrew Joyce", "recommendationsReceived/8/name": "Andrew Joyce", "recommendationsReceived/8/subtitle": "Head of Food & Beverage", "recommendationsReceived/8/url": "https://www.linkedin.com/in/andrew-joyce-2b77b426/", "recommendationsReceived/8/urn": "urn:li:fsd_profile:ACoAAAV1C6sBSO-WG-qp9z-lHMRUN8eN0KbSqPo", "skills/0/title": "Menu Development", "skills/1/title": "Mediterranean", "skills/2/title": "Italian", "skills/3/title": "Indian", "skills/4/title": "Arabic", "skills/5/title": "European Union", "skills/6/title": "Pre-opening", "skills/7/title": "Banquets", "skills/8/title": "Hotels", "skills/9/title": "Restaurants", "skills/10/title": "Resorts", "skills/11/title": "HACCP", "skills/12/title": "Food Preparation", "skills/13/title": "Training", "skills/14/title": "Project Planning", "skills/15/title": "Food & Beverage", "skills/16/title": "Yield Management", "skills/17/title": "Opening Hotels", "skills/18/title": "Hotel Management", "skills/19/title": "Food", "totalExperienceYears": "19.7", "totalRecommendationsGiven": "8", "totalRecommendationsReceived": "9", "urn": "ACoAAAOd9ZABbwoxuy7AYXKMR-WReMs3GlP5G2k"}$$::jsonb),
